// Extract search query from message
const message = $json.message || '';

// Remove JASA keyword and get search term
let query = message
  .replace(/jasa/gi, '')
  .replace(/tukang/gi, '')
  .replace(/servis/gi, '')
  .replace(/service/gi, '')
  .replace(/cari/gi, '')
  .trim();

if (!query || query.length < 2) {
  query = '';
}

return {
  json: {
    ...$json,
    query: query
  }
};

// Format Jasa results with phone masking
const data = $json.data || [];
const query = $('Extract Jasa Query').item.json.query;

const results = data.slice(0, 5);

if (results.length === 0) {
  return {
    json: {
      phone: $('Extract Jasa Query').item.json.phone,
      chatId: $('Extract Jasa Query').item.json.chatId,
      reply: `❌ *TIDAK DITEMUKAN*\n\nTidak ada jasa dengan kata kunci "${query}"\n\n💡 Coba kata kunci lain seperti:\n• Tukang\n• Servis AC\n• Montir\n• Piket`
    }
  };
}

let replyText = `🔧 *HASIL PENCARIAN JASA*\n`;
if (query) replyText += `Kata kunci: "${query}"\n`;
replyText += `Ditemukan: ${data.length} jasa\n`;
replyText += `───────────────────\n\n`;

results.forEach((item, index) => {
  const phone = item.whatsapp || item.phone || '';
  const maskedPhone = phone.length > 8 
    ? phone.substring(0, 4) + '****' + phone.substring(phone.length - 4)
    : phone;

  const waLink = `https://wa.me/${phone.replace(/[^0-9]/g, '')}`;

  replyText += `${index + 1}. *${item.nama_jasa || item.name}*\n`;
  replyText += `   📍 ${item.desa || item.alamat || '-'}\n`;
  if (item.keahlian || item.skill) {
    replyText += `   🔧 ${item.keahlian || item.skill}\n`;
  }
  replyText += `   📱 ${maskedPhone}\n`;
  replyText += `   🔗 [Hubungi via WA](${waLink})\n\n`;
});

if (data.length > 5) {
  replyText += `_...dan ${data.length - 5} lainnya_\n`;
}

replyText += `\n💡 Ketik JASA <jenis> untuk pencarian spesifik`;

return {
  json: {
    phone: $('Extract Jasa Query').item.json.phone,
    chatId: $('Extract Jasa Query').item.json.chatId,
    reply: replyText
  }
};

const replyText = `❌ *ERROR*\n\nGagal mencari data jasa. Silakan coba lagi nanti.\n\n💡 Ketik MENU untuk melihat daftar layanan.`;

return {
  json: {
    phone: $('Extract Jasa Query').item.json.phone,
    chatId: $('Extract Jasa Query').item.json.chatId,
    reply: replyText
  }
};
